import{_ as t}from"./chunks/build-datahubs.B9TbUNm6.js";import{_ as a,o as n,c as i,ag as o}from"./chunks/framework.ePeAWSvT.js";const s="/assets/modal-datahub-add.DX0OF8JZ.png",r="/assets/datahub-add-endpoint.BLNpOccP.png",f=JSON.parse('{"title":"Data Hubs","description":"","frontmatter":{},"headers":[],"relativePath":"guide/build-datahubs.md","filePath":"guide/build-datahubs.md"}'),d={name:"guide/build-datahubs.md"};function l(c,e,h,p,u,g){return n(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="data-hubs" tabindex="-1">Data Hubs <a class="header-anchor" href="#data-hubs" aria-label="Permalink to &quot;Data Hubs&quot;">​</a></h1><p>Data Hubs are versioned configurations that define how data flows between connected systems. Each hub connects the systems (endpoints) that have or need the data defined within your data models. You create a Data Hub by adding endpoints, configuring the actions each endpoint can execute, and then mapping endpoint actions to the common model. This ties all of the data together using your previously defined schema definitions and configured connectors.</p><p><img src="'+t+'" alt="Data Hubs Page"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Versioned Configurations</strong> — Maintain draft and live versions of your data hub configurations</li><li><strong>Publisher &amp; Subscriber Endpoints</strong> — Define how data is read from and written to connected systems</li><li><strong><a href="./datahub-action-mapping.html">Property Mapping</a></strong> — Map fields between your canonical data model and connector-specific formats</li><li><strong><a href="./datahub-scheduling.html">Scheduling</a></strong> — Configure when publishers run to collect data</li></ul><h2 id="build-a-data-hub" tabindex="-1">Build a Data Hub <a class="header-anchor" href="#build-a-data-hub" aria-label="Permalink to &quot;Build a Data Hub&quot;">​</a></h2><p><img src="'+s+'" alt="Add Data Hub Modal"></p><ol><li>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</li><li>Select <strong>+ Add</strong>.</li><li>Enter a <strong>Name</strong> for the new Data Hub.</li><li>Select <strong>Save</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li>When a new Data Hub is created, it is saved as a <strong>Draft</strong> version until deployed.</li><li>Once a Data Hub is created, you can select the <strong>edit</strong> icon to rename it if needed.</li></ul></div><h2 id="add-endpoints-to-a-data-hub" tabindex="-1">Add Endpoints to a Data Hub <a class="header-anchor" href="#add-endpoints-to-a-data-hub" aria-label="Permalink to &quot;Add Endpoints to a Data Hub&quot;">​</a></h2><p><img src="'+r+'" alt="Add Endpoint to Data Hub"></p><ol><li>Select <strong>Build</strong> &gt; <strong>Data Hubs</strong> from the main menu.</li><li>Select the appropriate <strong>Data Hub</strong> in the left column.</li><li>Select <strong>Actions</strong> &gt; <strong>Add Endpoint</strong>.</li><li>Select the appropriate <strong>Connector</strong>.</li><li>Select <strong>Next</strong>.</li><li>Then, use the guidance below to configure the endpoint using a template or manually.</li></ol><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><p>It is common to have multiple Transaction Types in the same Data Hub; however, it is best practice to keep all of the endpoints that are publishing and subscribing to the same Transaction Type grouped within the same Data Hub. See the <a href="./build-data-models.html">Data Models</a> section for additional information about Transaction Types.</p></div><h3 id="using-a-template" tabindex="-1">Using a Template <a class="header-anchor" href="#using-a-template" aria-label="Permalink to &quot;Using a Template&quot;">​</a></h3><p>Templates provide pre-configured mapping for some of the more common schema relationships for the selected endpoint and associated action. They are available for commonly built syncs (e.g. a <em>Customer</em> sync for NetSuite). If a template is available, it is strongly recommended to use one.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>If a template is not available for the selected connector, you will not see the <strong>Use Template</strong> toggle. You will need to manually build the endpoint settings and mapping.</p></div><ol><li>Toggle <strong>Use Template</strong> ON.</li><li>Select a <strong>Template</strong> from the drop-down menu. Once selected, a template description will appear below the menu.</li><li>Select a <strong>Schema</strong> from the drop-down menu (or select <strong>Create New Schema</strong>).</li><li>Select a <strong>Transaction Type</strong> from the drop-down menu. This drop-down is dependent on previous selections and will only appear once you click inside the field. If <strong>Create New Schema</strong> is selected, you will need to enter a new Transaction Type in the field.</li><li>As needed, toggle <strong>Customer Endpoint Host</strong> ON, then select a <strong>Host Type Extension</strong> from the drop-down menu.</li><li>Select <strong>Save</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>When using a template, you can select <strong>Show Changes</strong> to open a sliding panel showing the list of data models included in the template, including the individual schema properties. Select <strong>Close</strong> to close the panel.</p></div><h3 id="configuring-manually" tabindex="-1">Configuring Manually <a class="header-anchor" href="#configuring-manually" aria-label="Permalink to &quot;Configuring Manually&quot;">​</a></h3><ol><li>Enter an <strong>Endpoint Name</strong>. This field is simply a displayed label in the design view.</li><li>Select an <strong>Endpoint Type</strong> from the drop-down menu. See the <a href="#endpoint-types">Endpoint Types</a> section below for descriptions.</li><li>As needed, select a <strong>File Type</strong>. This field is only applicable for file-based connectors (e.g. FTP sites or local storage). See the <a href="#file-based-endpoint-encoding-types">File-based Endpoint Encoding Types</a> table below.</li><li>Select a <strong>Schema</strong> from the drop-down menu.</li><li>Select a <strong>Transaction Type</strong> from the drop-down menu. This drop-down is dependent on previous selections and will only appear once you click inside the field.</li><li>As needed, toggle <strong>Customer Endpoint Host</strong> ON, then select a <strong>Host Type Extension</strong> from the drop-down menu.</li><li>Select <strong>Save</strong>.</li></ol><p>Repeat this process to add as many endpoints as needed to a Data Hub.</p><h2 id="endpoint-types" tabindex="-1">Endpoint Types <a class="header-anchor" href="#endpoint-types" aria-label="Permalink to &quot;Endpoint Types&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><ul><li>A single-direction endpoint creates either a save action or a read action (e.g. Publish creates only a read action, while Subscribe creates only a save action).</li><li>A bi-directional endpoint creates both a save and read action.</li><li>When a save action is created, an interaction to the Key is automatically created.</li><li>A Webhook is a specific type of publishing endpoint where data is pushed from the connector to Central. Only certain vendors support this capability.</li><li>Data Provider is used when creating API Gateway endpoints and should not be selected when working within a Data Hub.</li></ul></div><table tabindex="0"><thead><tr><th>Endpoint Type</th><th>Description</th></tr></thead><tbody><tr><td>Batch Publish</td><td>Publishes a group of transactions together.</td></tr><tr><td>Batch Subscriber</td><td>Receives a group of transactions to be processed together.</td></tr><tr><td>Batch Subscribe Messages</td><td>Receives a group of messages and batches them together. It enables a publisher to run on a normal schedule; then, a subscriber can batch process the messages as needed (while other systems may get minute-to-minute updates). This is common in file-based protocols.</td></tr><tr><td>Both</td><td>Publish and subscribe the transaction.</td></tr><tr><td>Both with Webhooks</td><td>A bi-directional endpoint where the publisher is implemented using Webhooks.</td></tr><tr><td>Data Provider</td><td>A read-only endpoint used in the API Gateway. It is not intended to be used inside of a Data Hub.</td></tr><tr><td>Delete Publisher</td><td>A publishing endpoint specifically used to publish records to be deleted or inactivated across systems.</td></tr><tr><td>Publish</td><td>Triggers the publishing of data to be consumed by other systems that are listening for a particular Transaction Type.</td></tr><tr><td>Publish with Webhooks</td><td>A publisher that is implemented with Webhook capability.</td></tr><tr><td>Subscribe</td><td>Triggers the subscribing of data by systems listening for a particular Entity Type and Transaction Type.</td></tr></tbody></table><h2 id="file-based-endpoint-encoding-types" tabindex="-1">File-based Endpoint Encoding Types <a class="header-anchor" href="#file-based-endpoint-encoding-types" aria-label="Permalink to &quot;File-based Endpoint Encoding Types&quot;">​</a></h2><p>When configuring a file-based endpoint (e.g. FTP or local storage connectors), you must select an encoding type for the file.</p><table tabindex="0"><thead><tr><th>Encoding Type</th><th>Description</th></tr></thead><tbody><tr><td>UTF-8</td><td>Supports Unicode characters, while being backward compatible with ASCII.</td></tr><tr><td>UTF-8 (with BOM)</td><td>Supports Unicode characters, while being backward compatible with ASCII, including the BOM (Byte Order Mark). The BOM is a special character sequence placed at the beginning of the file to indicate the file is encoded in UTF-8. Some systems require the BOM to know what encoding to use for the characters.</td></tr></tbody></table><h2 id="endpoint-settings" tabindex="-1">Endpoint Settings <a class="header-anchor" href="#endpoint-settings" aria-label="Permalink to &quot;Endpoint Settings&quot;">​</a></h2><p>Each endpoint has a <strong>Settings</strong> tab where you can configure processing behavior, including receipt replication, key source overrides, change tracking, parallelism, supported operations, and engine behavior flags.</p><p>For full details on all available settings, see the dedicated <a href="./datahub-endpoint-settings.html">Endpoint Settings</a> page.</p>',30)])])}const y=a(d,[["render",l]]);export{f as __pageData,y as default};
